        console.info(`Completed tasks: ${completedTasks.length}/${expectedTaskIds.length}`);
        console.info(`Remaining tasks: ${pendingTasks.map((t) => t.id).join(", ")}`);
        allTasksCompleted = pendingTasks.length === 0;
